import{_ as a,o as t,c as r,a3 as o}from"./chunks/framework.oxq6d-og.js";const p=JSON.parse('{"title":"Windows x64 ABI and NThread","description":"","frontmatter":{},"headers":[],"relativePath":"en/architecture/windows-x64-abi.md","filePath":"en/architecture/windows-x64-abi.md"}'),n={name:"en/architecture/windows-x64-abi.md"};function s(d,e,i,c,h,l){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="windows-x64-abi-and-nthread" tabindex="-1">Windows x64 ABI and NThread <a class="header-anchor" href="#windows-x64-abi-and-nthread" aria-label="Permalink to &quot;Windows x64 ABI and NThread&quot;">​</a></h1><p>NThread must establish a valid Windows x64 register and stack state, not merely jump to a correct address.</p><h2 id="the-first-four-arguments-are-positional" tabindex="-1">The first four arguments are positional <a class="header-anchor" href="#the-first-four-arguments-are-positional" aria-label="Permalink to &quot;The first four arguments are positional&quot;">​</a></h2><p>Argument position chooses the register slot. Integer/pointer slots are <code>RCX</code>, <code>RDX</code>, <code>R8</code>, and <code>R9</code>; floating-point slots at the same positions are <code>XMM0</code>–<code>XMM3</code>. In a mixed signature, a second <code>f64</code> is in <code>XMM1</code>, not <code>XMM0</code>.</p><p>NThread writes normalized <code>f32</code> and <code>f64</code> arguments to the corresponding XMM slot and mirrors their bits into the matching general-purpose register field. Further arguments are stack slots. Integer/pointer returns come from <code>RAX</code>; floating-point returns come from <code>XMM0</code>.</p><h2 id="stack-and-return-chain" tabindex="-1">Stack and return chain <a class="header-anchor" href="#stack-and-return-chain" aria-label="Permalink to &quot;Stack and return chain&quot;">​</a></h2><p>The caller reserves 32 bytes of shadow space and preserves 16-byte alignment. NThread uses a workspace below the captured <code>RSP</code> and returns through an <code>add rsp, 0x28; ret</code> chain to its spin stub. Calls with more than four arguments use a temporary <code>add rsp, 0x28 + N*8; ret</code> cleanup stub.</p><p>Verify signatures before calling. Varargs, structs by value, SIMD/vector types, unusual conventions, and non-returning functions require controlled testing. If <code>expectedRsp</code> is set, NThread checks it after both async <code>call()</code> and <code>callSync()</code>.</p>',8)])])}const m=a(n,[["render",s]]);export{p as __pageData,m as default};
